const handleGameLoopError = (error: unknown, operationType: OperationType, path: string | null) => {
    // Ignore expected race conditions in the game loop
    if (
        operationType !== OperationType.DELETE &&
        error instanceof Error &&
        (error.message.includes('Missing or insufficient permissions') || error.message.includes('No document to update') || error.message.includes('NOT_FOUND'))
    ) {
        return;
    }
    handleFirestoreError(error, operationType, path);
};


