// Offline timer processing - calculates overdue building timers when player returns
// Track which buildings already had their offline timers synced to prevent duplicate DB writes
const _offlineTimersSynced = new Set<string>();
const processOfflineTimers = (
    buildings: PlacedBuilding[],
    options?: {
        canApplyDestructionTimer?: (building: PlacedBuilding) => boolean;
        resources?: MapResource[];
    }
): { updated: PlacedBuilding[], updates: { id: string, data: Partial<PlacedBuilding> }[] } => {
    const now = Date.now();
    const updated: PlacedBuilding[] = [];
    const updates: { id: string, data: Partial<PlacedBuilding> }[] = [];

    for (const building of buildings) {
        let needsUpdate = false;
        const updatedBuilding = { ...building };
        const bId = String(building.id);

        // Check construction timer
        if (building.isConstructing && building.constructionEndTime && now >= building.constructionEndTime) {
            updatedBuilding.isConstructing = false;
            updatedBuilding.workState = 'idle';
            needsUpdate = true;
        }

        // Check work timer (farming/production)
        if (building.workState === 'working' && building.workEndTime && now >= building.workEndTime) {
            updatedBuilding.workState = 'finished';
            needsUpdate = true;
        }

        // Check destruction/bomb timer
        if (
            building.isDestroying &&
            building.destructionEndTime &&
            now >= building.destructionEndTime &&
            (options?.canApplyDestructionTimer?.(building) ?? true)
        ) {
            const damage = building.pendingDamage || 0;
            // Use maxHp as fallback if hp is undefined Р Р†Р вЂљРІР‚Сњ never default to 0 which would
            // cause any pending damage to instantly kill a building with unknown HP.
            const info = buildingData.find(i => i.id === building.buildingId);
            const fullHp = building.maxHp ?? info?.stats.durability ?? 100;
            const currentHp = building.hp ?? fullHp;
            const remainingHp = currentHp - damage;
            
            updatedBuilding.hp = remainingHp;
            // Persist maxHp during destruction finalization so hp=0 cannot be
            // misread as a migration artifact and restored on next sync.
            updatedBuilding.maxHp = fullHp;
            updatedBuilding.isDestroying = false;
            updatedBuilding.destructionEndTime = undefined;
            updatedBuilding.pendingDamage = 0;
            
            // If HP <= 0, mark for deletion (don't delete here, let the game loop handle it)
            if (remainingHp <= 0) {
                updatedBuilding.hp = 0;
            }
            needsUpdate = true;
        }

        if (needsUpdate) {
            updated.push(updatedBuilding);
            
            // Only push DB update if we haven't already synced this building's timer
            if (!_offlineTimersSynced.has(bId)) {
                _offlineTimersSynced.add(bId);
                const updateData: Partial<PlacedBuilding> = {};
                
                if (updatedBuilding.isConstructing !== building.isConstructing) {
                    updateData.isConstructing = updatedBuilding.isConstructing;
                }
                if (updatedBuilding.workState !== building.workState) {
                    updateData.workState = updatedBuilding.workState;
                }
                if (updatedBuilding.isDestroying !== building.isDestroying) {
                    updateData.isDestroying = updatedBuilding.isDestroying;
                }
                if (updatedBuilding.destructionEndTime !== building.destructionEndTime) {
                    updateData.destructionEndTime = updatedBuilding.destructionEndTime;
                }
                if (updatedBuilding.pendingDamage !== building.pendingDamage) {
                    updateData.pendingDamage = updatedBuilding.pendingDamage;
                }
                if (updatedBuilding.hp !== building.hp) {
                    updateData.hp = updatedBuilding.hp;
                }
                if (updatedBuilding.maxHp !== building.maxHp) {
                    updateData.maxHp = updatedBuilding.maxHp;
                }
                
                updates.push({ id: bId, data: updateData });
            }
        } else {
            // Building timer no longer overdue (server caught up) - allow future re-sync
            _offlineTimersSynced.delete(bId);
        }
    }

    // OFFLINE COMBAT CATCH-UP:
    // Simulate missed monster attacks while players were offline.
    // We currently simulate attack ticks only for monsters already adjacent to a target.
    const byId = new Map<string, PlacedBuilding>();
    buildings.forEach((b) => byId.set(String(b.id), { ...b }));
    const blockedResourcePositions = new Set(
        (options?.resources || []).map(r => `${r.x},${r.y}`)
    );

    const neighbors4 = (a: PlacedBuilding, b: PlacedBuilding) =>
        Math.abs(a.x - b.x) + Math.abs(a.y - b.y) === 1;

    const nowTs = now;
    const MAX_OFFLINE_COMBAT_WINDOW_MS = 60 * 1000; // keep catch-up small to avoid burst deletes after lag/tab freeze
    const MAX_OFFLINE_MOVE_WINDOW_MS = 60 * 1000; // keep movement catch-up bounded too
    const MAX_OFFLINE_TOTAL_HITS = 20000; // global safety cap
    const MAX_OFFLINE_HITS_PER_MONSTER = 3; // per-sync cap, smooths damage for online feel
    const MAX_OFFLINE_TOTAL_MOVES = 5000; // global safety cap for movement catch-up
    const MAX_OFFLINE_MOVES_PER_MONSTER = 3; // per-sync cap, smooths position jumps
    let appliedHits = 0;
    let appliedMoves = 0;

    const monsters = Array.from(byId.values()).filter((b) => {
        const info = buildingData.find(i => i.id === b.buildingId);
        return !!info?.stats.isMonster && (b.hp === undefined || b.hp > 0);
    });

    const getAliveOccupiedPositions = () => new Set(
        Array.from(byId.values())
            .filter(b => b.hp === undefined || b.hp > 0)
            .map(b => `${b.x},${b.y}`)
    );

    for (const monster of monsters) {
        if (appliedHits >= MAX_OFFLINE_TOTAL_HITS) break;
        const monsterId = String(monster.id);
        const target = getMonsterAdjacentAttackTarget(monster, Array.from(byId.values()), buildingData);
        if (!target) continue;

        const monsterInfo = buildingData.find(i => i.id === monster.buildingId);
        let dmg = monsterInfo?.stats.damage ? parseInt(monsterInfo.stats.damage) : 4;
        const targetInfo = buildingData.find(i => i.id === target.buildingId);
        if (monsterInfo?.stats.hates && targetInfo?.category === monsterInfo.stats.hates) {
            dmg *= 2;
        }

        const lastAttack = monster.lastAttackTime || 0;
        const elapsedRaw = Math.max(0, nowTs - lastAttack);
        const elapsed = Math.min(elapsedRaw, MAX_OFFLINE_COMBAT_WINDOW_MS);
        const availableHits = Math.floor(elapsed / MONSTER_ATTACK_INTERVAL_MS);
        if (availableHits <= 0) continue;

        const targetId = String(target.id);
        const targetCurrent = byId.get(targetId);
        if (!targetCurrent) continue;
        const targetBaseHp = targetCurrent.hp ?? (targetInfo?.stats.durability ?? 100);
        if (targetBaseHp <= 0) continue;

        const targetBaseShield = Math.max(0, Number(targetCurrent.shieldHp) || 0);
        const maxHitsByShieldAndHp = Math.max(0, Math.ceil((targetBaseShield + targetBaseHp) / Math.max(1, dmg)));
        const hitsLeftGlobal = MAX_OFFLINE_TOTAL_HITS - appliedHits;
        const hits = Math.max(0, Math.min(availableHits, maxHitsByShieldAndHp, hitsLeftGlobal, MAX_OFFLINE_HITS_PER_MONSTER));
        if (hits <= 0) continue;

        // Respect combat rule during catch-up too: shield must be depleted before HP damage.
        let remainingHits = hits;
        let nextShield = targetBaseShield;
        let nextHp = targetBaseHp;
        while (remainingHits > 0 && nextShield > 0) {
            nextShield = Math.max(0, nextShield - dmg);
            remainingHits--;
        }
        if (remainingHits > 0) {
            nextHp = Math.max(0, nextHp - remainingHits * dmg);
        }

        const monsterFatalHit = nextHp <= 0;
        const targetMaxHp = targetCurrent.maxHp ?? (targetInfo?.stats.durability ?? 100);

        byId.set(targetId, {
            ...targetCurrent,
            hp: monsterFatalHit ? targetBaseHp : nextHp,
            maxHp: targetMaxHp,
            shieldHp: nextShield > 0 ? nextShield : undefined,
            shieldMaxHp: nextShield > 0 ? targetCurrent.shieldMaxHp : undefined,
            protectionEndTime: nextShield > 0 ? targetCurrent.protectionEndTime : undefined,
            isDestroying: monsterFatalHit,
            destructionEndTime: monsterFatalHit ? (nowTs + MONSTER_FATAL_HIT_DELAY_MS) : undefined,
            pendingDamage: monsterFatalHit ? targetBaseHp : 0
        });
        byId.set(monsterId, { ...monster, lastAttackTime: nowTs });

        updates.push({
            id: targetId,
            data: {
                hp: monsterFatalHit ? targetBaseHp : nextHp,
                maxHp: targetMaxHp,
                shieldHp: nextShield > 0 ? nextShield : undefined,
                shieldMaxHp: nextShield > 0 ? targetCurrent.shieldMaxHp : undefined,
                protectionEndTime: nextShield > 0 ? targetCurrent.protectionEndTime : undefined,
                isDestroying: monsterFatalHit,
                destructionEndTime: monsterFatalHit ? (nowTs + MONSTER_FATAL_HIT_DELAY_MS) : undefined,
                pendingDamage: monsterFatalHit ? targetBaseHp : 0
            }
        });
        updates.push({ id: monsterId, data: { lastAttackTime: nowTs } });
        appliedHits += hits;
    }

    // Merge combat updates into `updated` return list
    const updatedIds = new Set(updated.map((b) => String(b.id)));
    byId.forEach((b, id) => {
        const original = buildings.find(src => String(src.id) === id);
        if (!original) return;
        if (
            b.x !== original.x ||
            b.y !== original.y ||
            b.zoneId !== original.zoneId ||
            b.lastMoveTime !== original.lastMoveTime ||
            b.hp !== original.hp ||
            b.lastAttackTime !== original.lastAttackTime ||
            b.shieldHp !== original.shieldHp ||
            b.shieldMaxHp !== original.shieldMaxHp ||
            b.protectionEndTime !== original.protectionEndTime
        ) {
            if (updatedIds.has(id)) {
                const idx = updated.findIndex(u => String(u.id) === id);
                if (idx >= 0) updated[idx] = b;
            } else {
                updated.push(b);
            }
        }
    });

    return { updated, updates };
};

