    // Sync allUsersRef
    useEffect(() => { allUsersRef.current = allUsers; }, [allUsers]);

    // Fast owner hydration for building card: avoids long "Unknown player" waits on slow zone batches.
    useEffect(() => {
        const ownerId = selectedBuilding?.building?.ownerId as string | undefined;
        if (!ownerId || ownerId === "-1" || ownerId === "monster" || ownerId === "0" || ownerId === GUEST_ID) return;
        if (missingOwnersRef.current.has(ownerId)) return;
        if (allUsersRef.current[ownerId]) return;
        // Avoid hammering PB for missing/deleted owners when selection updates frequently.
        const OWNER_HYDRATION_CACHE_MS = 5 * 60 * 1000;
        const lastFetchTs = fetchedOwnersRef.current.get(ownerId) || 0;
        if ((Date.now() - lastFetchTs) < OWNER_HYDRATION_CACHE_MS) return;

        let cancelled = false;
        (async () => {
            try {
                const userDoc = await getDoc(doc(db, 'users', ownerId));
                if (!userDoc.exists() || cancelled) {
                    fetchedOwnersRef.current.set(ownerId, Date.now());
                    return;
                }
                const userData = userDoc.data();
                setAllUsers(prev => ({
                    ...prev,
                    [ownerId]: {
                        uid: ownerId,
                        name: userData.name || selectedBuilding?.building?.ownerName || 'Р СњР ВµР С‘Р В·Р Р†Р ВµРЎРѓРЎвЂљР Р…РЎвЂ№Р в„–',
                        level: userData.level || 1,
                        glory: userData.glory || 0,
                        reputation: userData.reputation || 0,
                        avatar: userData.data?.avatar || userData.avatar || null,
                        clanId: userData.clanId || null,
                        rank: userData.rank ?? 0,
                        clanPermissions: userData.clanPermissions || { canInvite: false, canGrantStars: false }
                    }
                }));
                fetchedOwnersRef.current.set(ownerId, Date.now());
            } catch (err) {
                console.warn(`[OwnerHydration] Failed to fetch owner ${ownerId}:`, err);
                if ((err as any)?.status === 404) {
                    missingOwnersRef.current.add(ownerId);
                    // Push next retry far into the future for hard-missing records.
                    fetchedOwnersRef.current.set(ownerId, Date.now() + MISSING_OWNER_TTL_MS);
                    return;
                }
                // Cache failed lookups too, so deleted/unknown users don't spam repeated 404 fetches.
                fetchedOwnersRef.current.set(ownerId, Date.now());
            }
        })();

        return () => { cancelled = true; };
    }, [selectedBuilding, db]);
    
    // Sync camera and zoom refs for beforeunload
    useEffect(() => { cameraOffsetRef.current = cameraOffset; }, [cameraOffset]);
    useEffect(() => { zoomIndexRef.current = zoomIndex; }, [zoomIndex]);


