    // Loading screen: hybrid progress (timer + actual data readiness)
    // Progress bar fills to ~70% on timer, then jumps to 100% when data arrives
    // For fast connections: bar fills quickly, data loads fast, user sees "press to begin" around 70%+
    // For slow connections: bar hits 70% and waits, continues when data loads, never stalls at 100%
    const loadTimerDone = useRef(false);
    const loadStartTime = useRef(Date.now());
    const MIN_LOADING_TIME_MS = 5000; // Minimum 5s for assets to preload in background
    useEffect(() => {
        // Phase 1: Fill to 70% quickly (timer-based)
        const interval = setInterval(() => {
            setLoadingProgress(p => {
                // Stop at 70% - last 30% comes from actual data loading
                if (p >= 70) {
                    // If data already loaded, fill to 100%
                    if (loadPhaseRef.current >= 1) {
                        if (p >= 100) {
                            clearInterval(interval);
                            return 100;
                        }
                        return Math.min(p + 5, 100); // Fast fill to 100%
                    }
                    return 70; // Hold at 70% waiting for data
                }
                return p + 3;
            });
        }, 200);

        let timeout: NodeJS.Timeout;
        if (user) {
            timeout = setTimeout(() => {
                loadTimerDone.current = true;
                // Only set ready if critical data has also loaded (loadPhase >= 1)
                if (loadPhaseRef.current >= 1) {
                    setLoadingReady(true);
                }
            }, 15000); // 15 seconds maximum loading time
        }

        return () => {
            clearInterval(interval);
            if (timeout) clearTimeout(timeout);
        };
    }, [user]);

